#include <iostream>
#include <string>
#include <sstream>
#include <streambuf>
#include <vector>

// This function simulates running the main program with given input and captures its output.
// In a real testing environment, the user's code would be compiled into an executable
// and run as a separate process, with stdin/stdout redirected.
// For the purpose of this JSON field, this C++ snippet illustrates the I/O redirection concept.
std::string run_program_and_capture_output(const std::string& input_str, int (*program_main)()) {
    std::stringstream input_stream(input_str);
    std::stringstream output_stream;

    // Save original streambufs
    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    // Redirect cin and cout
    std::cin.rdbuf(input_stream.rdbuf());
    std::cout.rdbuf(output_stream.rdbuf());

    // Call the program's main function (conceptually)
    // In a real test, 'program_main()' would be replaced by executing the compiled binary.
    program_main();

    // Restore original streambufs
    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return output_stream.str();
}

